SELECT gs.summary_id AS summaryId, gs.selection_id AS selectionId, gs.student_id AS studentId, su.real_name AS studentName, su.student_no AS studentNo, pt.topic_name AS topicName, ps.custom_topic_name AS customTopicName, ps.is_custom_topic AS isCustomTopic, ps.teacher_id AS teacherId, tu.real_name AS teacherName, ps.campus_name AS campusName, ps.academic_year AS academicYear, gs.evaluator_count AS evaluatorCount, gs.avg_regular_score AS avgRegularScore, gs.avg_thesis_score AS avgThesisScore, gs.avg_defense_score AS avgDefenseScore, gs.total_score AS totalScore, gs.grade_level AS gradeLevel, gs.adjusted_total_score AS adjustedTotalScore, gs.final_score AS finalScore, gs.adjusted_grade_level AS adjustedGradeLevel, gs.final_grade_level AS finalGradeLevel, gs.is_adjusted AS isAdjusted, gs.is_locked AS isLocked, gs.remark AS remark, gs.lock_time AS lockTime, lu.real_name AS lockedByName, gs.create_time AS createTime FROM grade_summary gs INNER JOIN project_selection ps ON gs.selection_id = ps.selection_id AND ps.is_deleted = 0 INNER JOIN sys_user su ON gs.student_id = su.user_id AND su.is_deleted = 0 LEFT JOIN project_topic pt ON pt.topic_id = ps.topic_id AND pt.is_deleted = 0 LEFT JOIN sys_user tu ON ps.teacher_id = tu.user_id AND tu.is_deleted = 0 LEFT JOIN sys_user lu ON gs.locked_by = lu.user_id AND lu.is_deleted = 0 WHERE gs.is_deleted = 0
AND ps.campus_name = #{campusName}
AND ps.academic_year = #{academicYear}
AND (su.real_name LIKE CONCAT('%', #{keyword}, '%') OR su.student_no LIKE CONCAT('%', #{keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{keyword}, '%') OR ps.custom_topic_name LIKE CONCAT('%', #{keyword}, '%'))
AND gs.final_grade_level = #{gradeLevel}
ORDER BY gs.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(gs.summary_id) FROM grade_summary gs INNER JOIN project_selection ps ON gs.selection_id = ps.selection_id AND ps.is_deleted = 0 INNER JOIN sys_user su ON gs.student_id = su.user_id AND su.is_deleted = 0 LEFT JOIN project_topic pt ON pt.topic_id = ps.topic_id AND pt.is_deleted = 0 WHERE gs.is_deleted = 0
AND ps.campus_name = #{campusName}
AND ps.academic_year = #{academicYear}
AND (su.real_name LIKE CONCAT('%', #{keyword}, '%') OR su.student_no LIKE CONCAT('%', #{keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{keyword}, '%') OR ps.custom_topic_name LIKE CONCAT('%', #{keyword}, '%'))
AND gs.final_grade_level = #{gradeLevel}

